import React, { useState, useEffect } from 'react';
import { ordersAPI } from '../api';
//import './OrdersPage.css';

const OrdersPage = ({ user, orders = [], setOrders, setCurrentPage }) => {
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [filterStatus, setFilterStatus] = useState('all');

    useEffect(() => {
        loadOrders();
    }, []);

    const loadOrders = async () => {
        try {
            setLoading(true);
            setError('');
            const response = await ordersAPI.history();
            setOrders(response.data || []);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to load orders');
            console.error('Error loading orders:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleCancelOrder = async (orderId) => {
        if (!window.confirm('Are you sure you want to cancel this order?')) return;

        try {
            setLoading(true);
            await ordersAPI.cancel(orderId);
            setError('');
            await loadOrders();
            setSelectedOrder(null);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to cancel order');
        } finally {
            setLoading(false);
        }
    };

    const filteredOrders = filterStatus === 'all' 
        ? orders 
        : orders.filter(order => order.status?.toLowerCase() === filterStatus.toLowerCase());

    const getStatusBadgeClass = (status) => {
        const statusLower = status?.toLowerCase() || '';
        if (statusLower === 'delivered') return 'badge-success';
        if (statusLower === 'pending') return 'badge-warning';
        if (statusLower === 'cancelled') return 'badge-danger';
        if (statusLower === 'processing') return 'badge-info';
        if (statusLower === 'shipped') return 'badge-primary';
        return 'badge-secondary';
    };

    return (
        <div className="orders-page">
            <div className="orders-header">
                <h1>My Orders</h1>
                <button 
                    className="btn btn-primary"
                    onClick={() => setCurrentPage('products')}
                >
                    Continue Shopping
                </button>
            </div>

            {error && <div className="alert alert-danger">{error}</div>}

            {!selectedOrder ? (
                <>
                    {/* Filter Tabs */}
                    <div className="filter-tabs">
                        {['all', 'pending', 'processing', 'shipped', 'delivered', 'cancelled'].map(status => (
                            <button
                                key={status}
                                className={`filter-tab ${filterStatus === status ? 'active' : ''}`}
                                onClick={() => setFilterStatus(status)}
                            >
                                {status.charAt(0).toUpperCase() + status.slice(1)}
                            </button>
                        ))}
                    </div>

                    {/* Orders List */}
                    {loading ? (
                        <div className="loading">Loading orders...</div>
                    ) : filteredOrders.length === 0 ? (
                        <div className="empty-state">
                            <p>No orders found</p>
                            <button 
                                className="btn btn-primary"
                                onClick={() => setCurrentPage('products')}
                            >
                                Start Shopping
                            </button>
                        </div>
                    ) : (
                        <div className="orders-list">
                            {filteredOrders.map(order => (
                                <div key={order._id || order.Id} className="order-card">
                                    <div className="order-header">
                                        <div className="order-info">
                                            <h3>Order {order.orderNumber || order.OrderNumber || order._id?.substring(0, 8)}</h3>
                                            <p className="order-date">
                                                {new Date(order.createdAt || order.CreatedAt).toLocaleDateString()}
                                            </p>
                                        </div>
                                        <div className={`status-badge ${getStatusBadgeClass(order.status || order.Status)}`}>
                                            {order.status || order.Status || 'Pending'}
                                        </div>
                                    </div>

                                    <div className="order-items-preview">
                                        {order.items?.slice(0, 3).map((item, idx) => (
                                            <div key={idx} className="item-preview">
                                                <img 
                                                    src={item.productImage || item.ProductImage || 'https://via.placeholder.com/80'} 
                                                    alt={item.productName}
                                                    onError={(e) => e.target.src = 'https://via.placeholder.com/80'}
                                                />
                                                <div className="item-details">
                                                    <p className="item-name">{item.productName || item.ProductName}</p>
                                                    <p className="item-qty">Qty: {item.quantity || item.Quantity}</p>
                                                </div>
                                            </div>
                                        ))}
                                        {order.items?.length > 3 && (
                                            <p className="items-more">+{order.items.length - 3} more</p>
                                        )}
                                    </div>

                                    <div className="order-footer">
                                        <div className="order-total">
                                            <span>Total:</span>
                                            <strong>₹{(order.totalAmount || order.TotalAmount || 0).toFixed(2)}</strong>
                                        </div>
                                        <button 
                                            className="btn btn-secondary"
                                            onClick={() => setSelectedOrder(order)}
                                        >
                                            View Details
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </>
            ) : (
                // Order Details View
                <div className="order-details">
                    <button 
                        className="btn-back"
                        onClick={() => setSelectedOrder(null)}
                    >
                        ← Back to Orders
                    </button>

                    <div className="details-header">
                        <h2>Order {selectedOrder.orderNumber || selectedOrder.OrderNumber}</h2>
                        <div className={`status-badge large ${getStatusBadgeClass(selectedOrder.status || selectedOrder.Status)}`}>
                            {selectedOrder.status || selectedOrder.Status}
                        </div>
                    </div>

                    <div className="details-grid">
                        {/* Order Items */}
                        <div className="section">
                            <h3>Order Items</h3>
                            <div className="items-table">
                                {selectedOrder.items?.map((item, idx) => (
                                    <div key={idx} className="item-row">
                                        <img 
                                            src={item.productImage || item.ProductImage || 'https://via.placeholder.com/100'} 
                                            alt={item.productName}
                                            onError={(e) => e.target.src = 'https://via.placeholder.com/100'}
                                        />
                                        <div className="item-info">
                                            <p className="name">{item.productName || item.ProductName}</p>
                                            <p className="price">₹{(item.price || item.Price || 0).toFixed(2)}</p>
                                        </div>
                                        <div className="qty">Qty: {item.quantity || item.Quantity}</div>
                                        <div className="subtotal">
                                            ₹{((item.price || item.Price || 0) * (item.quantity || item.Quantity)).toFixed(2)}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Shipping Address */}
                        <div className="section">
                            <h3>Shipping Address</h3>
                            <div className="address-box">
                                <p><strong>{selectedOrder.shippingAddress?.name || selectedOrder.ShippingAddress?.Name}</strong></p>
                                <p>{selectedOrder.shippingAddress?.street || selectedOrder.ShippingAddress?.Street}</p>
                                <p>{selectedOrder.shippingAddress?.city || selectedOrder.ShippingAddress?.City}</p>
                                <p>{selectedOrder.shippingAddress?.state || selectedOrder.ShippingAddress?.State} - {selectedOrder.shippingAddress?.zipCode || selectedOrder.ShippingAddress?.ZipCode}</p>
                                <p>📞 {selectedOrder.shippingAddress?.phone || selectedOrder.ShippingAddress?.Phone}</p>
                            </div>
                        </div>

                        {/* Order Summary */}
                        <div className="section">
                            <h3>Order Summary</h3>
                            <div className="summary-box">
                                <div className="summary-row">
                                    <span>Subtotal:</span>
                                    <span>₹{(selectedOrder.subtotal || selectedOrder.Subtotal || 0).toFixed(2)}</span>
                                </div>
                                <div className="summary-row">
                                    <span>Discount:</span>
                                    <span>-₹{(selectedOrder.discount || selectedOrder.Discount || 0).toFixed(2)}</span>
                                </div>
                                <div className="summary-row">
                                    <span>Shipping:</span>
                                    <span>₹{(selectedOrder.shipping || selectedOrder.Shipping || 0).toFixed(2)}</span>
                                </div>
                                <div className="summary-row">
                                    <span>Tax:</span>
                                    <span>₹{(selectedOrder.tax || selectedOrder.Tax || 0).toFixed(2)}</span>
                                </div>
                                <div className="summary-row total">
                                    <span>Total:</span>
                                    <span>₹{(selectedOrder.totalAmount || selectedOrder.TotalAmount || 0).toFixed(2)}</span>
                                </div>
                            </div>
                        </div>

                        {/* Order Timeline */}
                        <div className="section full-width">
                            <h3>Order Timeline</h3>
                            <div className="timeline">
                                <div className={`timeline-item ${selectedOrder.status?.toLowerCase() === 'pending' || !selectedOrder.status ? 'active' : 'completed'}`}>
                                    <div className="timeline-dot"></div>
                                    <div className="timeline-content">
                                        <p className="timeline-title">Order Placed</p>
                                        <p className="timeline-date">{new Date(selectedOrder.createdAt || selectedOrder.CreatedAt).toLocaleString()}</p>
                                    </div>
                                </div>
                                <div className={`timeline-item ${['processing', 'shipped', 'delivered'].includes(selectedOrder.status?.toLowerCase()) ? 'completed' : ''}`}>
                                    <div className="timeline-dot"></div>
                                    <div className="timeline-content">
                                        <p className="timeline-title">Processing</p>
                                    </div>
                                </div>
                                <div className={`timeline-item ${['shipped', 'delivered'].includes(selectedOrder.status?.toLowerCase()) ? 'completed' : ''}`}>
                                    <div className="timeline-dot"></div>
                                    <div className="timeline-content">
                                        <p className="timeline-title">Shipped</p>
                                    </div>
                                </div>
                                <div className={`timeline-item ${selectedOrder.status?.toLowerCase() === 'delivered' ? 'completed' : ''}`}>
                                    <div className="timeline-dot"></div>
                                    <div className="timeline-content">
                                        <p className="timeline-title">Delivered</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="action-buttons">
                        {!['delivered', 'cancelled'].includes(selectedOrder.status?.toLowerCase() || '') && (
                            <button 
                                className="btn btn-danger"
                                onClick={() => handleCancelOrder(selectedOrder._id || selectedOrder.Id)}
                                disabled={loading}
                            >
                                {loading ? 'Cancelling...' : 'Cancel Order'}
                            </button>
                        )}
                        <button 
                            className="btn btn-secondary"
                            onClick={() => setCurrentPage('products')}
                        >
                            Continue Shopping
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default OrdersPage;
